import{_ as a,o as e,c as i,a2 as n}from"./chunks/framework.C24VBsJ9.js";const b=JSON.parse('{"title":"脚本设计拆解 - Bash 怎么把零件拼成一块盘","description":"","frontmatter":{},"headers":[],"relativePath":"tutorial/flash/06_build_imx6ull_image_script.md","filePath":"tutorial/flash/06_build_imx6ull_image_script.md","lastUpdated":1780980021000}'),p={name:"tutorial/flash/06_build_imx6ull_image_script.md"};function t(l,s,d,r,o,h){return e(),i("div",null,[...s[0]||(s[0]=[n(`<h1 id="脚本设计拆解-bash-怎么把零件拼成一块盘" tabindex="-1">脚本设计拆解 - Bash 怎么把零件拼成一块盘 <a class="header-anchor" href="#脚本设计拆解-bash-怎么把零件拼成一块盘" aria-label="Permalink to &quot;脚本设计拆解 - Bash 怎么把零件拼成一块盘&quot;">​</a></h1><h2 id="前言-脚本不是魔法-只是把手工步骤固定下来" tabindex="-1">前言：脚本不是魔法，只是把手工步骤固定下来 <a class="header-anchor" href="#前言-脚本不是魔法-只是把手工步骤固定下来" aria-label="Permalink to &quot;前言：脚本不是魔法，只是把手工步骤固定下来&quot;">​</a></h2><p>如果你第一次打开 <code>scripts/image_builder/build_imx6ull_image.sh</code>，可能会觉得它做的事情有点多：解析参数、找文件、算大小、做 ext4、写分区表、写 U-Boot、生成 manifest。</p><p>但别被这些函数名吓住。这个脚本的核心思路其实很简单：</p><p><strong>把我们原本手工烧录前要做的准备工作，变成一套稳定的、可重复执行的流程。</strong></p><p>我们不计划发明新的启动方式（没有任何收益，咱们是工程师，先把问题搞定了，再把问题解决优雅，是一种很常见的处理问题的方式，尽管往往我们不会做第二步（笑）），也不是在改变 U-Boot 或 Linux 的规则。它只是按照上一章的布局，把 U-Boot、内核、设备树和 rootfs 放到该放的位置。</p><p>我们这一章就顺着脚本的执行顺序走一遍，看它每一步为什么这么写。</p><h2 id="先看脚本的输入和输出" tabindex="-1">先看脚本的输入和输出 <a class="header-anchor" href="#先看脚本的输入和输出" aria-label="Permalink to &quot;先看脚本的输入和输出&quot;">​</a></h2><p>脚本默认从这里取材料：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/</span></span>
<span class="line"><span>├── uboot/u-boot-dtb.imx</span></span>
<span class="line"><span>├── linux/arch/arm/boot/zImage</span></span>
<span class="line"><span>├── linux/arch/arm/boot/dts/nxp/imx/imx6ull-aes.dtb</span></span>
<span class="line"><span>└── rootfs/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>然后把成品放到：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>out/release-latest/images/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>默认情况下，目标介质是 eMMC，所以输出文件名是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imx6ull-aes-emmc.img</span></span>
<span class="line"><span>imx6ull-aes-emmc.img.manifest</span></span>
<span class="line"><span>imx6ull-aes-emmc.img.sha256</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>如果你指定 SD：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/image_builder/build_imx6ull_image.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --boot-media=sd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>输出就变成：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imx6ull-aes-sd.img</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一步看起来只是换名字，但背后会影响启动命令里的 <code>mmc</code> 设备号和 Linux 的 <code>root=</code> 参数。</p><h2 id="第一步-先把用户意图问清楚" tabindex="-1">第一步：先把用户意图问清楚 <a class="header-anchor" href="#第一步-先把用户意图问清楚" aria-label="Permalink to &quot;第一步：先把用户意图问清楚&quot;">​</a></h2><p>脚本一开始做的是参数解析。它支持两种写法：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--release-dir</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">out/release-latest</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--release-dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> out/release-latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这些参数里，最常用的是：</p><table tabindex="0"><thead><tr><th>参数</th><th>你在告诉脚本什么</th></tr></thead><tbody><tr><td><code>--release-dir</code></td><td>从哪个 release 目录拿材料</td></tr><tr><td><code>--device-tree</code></td><td>使用哪个 DTB</td></tr><tr><td><code>--boot-media</code></td><td>生成 SD 还是 eMMC 镜像</td></tr><tr><td><code>--image-name</code></td><td>输出文件要叫什么</td></tr><tr><td><code>--boot-size-mb</code></td><td>boot 分区要多大</td></tr><tr><td><code>--rootfs-size-mb</code></td><td>rootfs 分区要多大</td></tr><tr><td><code>--image-size-mb</code></td><td>整个镜像要多大</td></tr></tbody></table><p>还有几个环境变量可以当默认值：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEFAULT_DEVICE_TREE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">imx6ull-aes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEFAULT_BOOT_MEDIA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">emmc</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEFAULT_IMAGE_SIZE_MB</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1024</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这几个环境变量适合放在 CI 或你自己的构建习惯里。比如你一直做 SD 卡镜像，就不用每次都敲 <code>--boot-media=sd</code>。</p><h2 id="第二步-sd-和-emmc-先分清楚" tabindex="-1">第二步：SD 和 eMMC 先分清楚 <a class="header-anchor" href="#第二步-sd-和-emmc-先分清楚" aria-label="Permalink to &quot;第二步：SD 和 eMMC 先分清楚&quot;">​</a></h2><p>脚本里有一个函数叫 <code>resolve_boot_media</code>。它做的事情非常朴素：把 <code>sd</code> 和 <code>emmc</code> 翻译成启动时真正需要的设备号。</p><p>当前项目约定是：</p><table tabindex="0"><thead><tr><th>参数</th><th>U-Boot 设备</th><th>Linux root</th></tr></thead><tbody><tr><td><code>--boot-media=sd</code></td><td><code>mmc 0</code></td><td><code>/dev/mmcblk0p2</code></td></tr><tr><td><code>--boot-media=emmc</code></td><td><code>mmc 1</code></td><td><code>/dev/mmcblk1p2</code></td></tr></tbody></table><p>这一步必须放得很早。因为后面生成 <code>boot.cmd</code>、manifest、手动启动命令，都要用这两个值。</p><p>如果用户传了一个脚本不认识的介质，比如：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--boot-media</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">nand</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>脚本会直接退出。这里不要“猜”。启动介质猜错了，生成出来的镜像反而更危险。</p><h2 id="第三步-把材料找齐" tabindex="-1">第三步：把材料找齐 <a class="header-anchor" href="#第三步-把材料找齐" aria-label="Permalink to &quot;第三步：把材料找齐&quot;">​</a></h2><p>接下来脚本进入 <code>resolve_artifacts</code>，开始检查材料。</p><p>它会找这些文件：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;release&gt;/uboot/u-boot-dtb.imx</span></span>
<span class="line"><span>&lt;release&gt;/linux/arch/arm/boot/zImage</span></span>
<span class="line"><span>&lt;release&gt;/linux/arch/arm/boot/dts/nxp/imx/&lt;dtb&gt;.dtb</span></span>
<span class="line"><span>&lt;release&gt;/rootfs/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>这里有两个小设计值得注意。</p><p>第一个是路径会转成绝对路径。这样 manifest 里记录出来的内容更明确，不会因为你从不同目录运行脚本而变得含糊。</p><p>第二个是 <code>--device-tree</code> 既可以是名字，也可以是路径。</p><p>如果你写：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--device-tree</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">imx6ull-aes</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>脚本会去 release 的 Linux 输出目录里找：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imx6ull-aes.dtb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你写：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--device-tree</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/custom.dtb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>脚本就直接使用这个文件。</p><p>这个设计对驱动教程很有用。比如你为某一章驱动实验单独编了一个 DTB，就可以直接把路径传给镜像脚本，不一定非要覆盖 release 里的默认 DTB。</p><h2 id="第四步-算大小-别让文件系统装不下" tabindex="-1">第四步：算大小，别让文件系统装不下 <a class="header-anchor" href="#第四步-算大小-别让文件系统装不下" aria-label="Permalink to &quot;第四步：算大小，别让文件系统装不下&quot;">​</a></h2><p>镜像大小是脚本里最容易让人误会的部分。</p><p>脚本先看内核和 DTB 有多大，确保 boot 分区至少能装下它们。默认 boot 分区是 64 MiB，一般够用。如果用户把 <code>--boot-size-mb</code> 设得太小，脚本会自动往上调。</p><p>然后脚本计算 rootfs。</p><p>默认情况下，它会用：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rootfs 实际占用 + 25% + 64 MiB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这个算法不复杂，但很实用。rootfs 不能刚刚好，刚刚好就意味着上板后很快写满；但默认也不应该动不动生成几个 GiB 的镜像。</p><p>如果你明确想要固定总镜像大小，比如 1 GiB：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/image_builder/build_imx6ull_image.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image-size-mb=1024</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>脚本会把镜像总大小固定成 1024 MiB，然后把剩余空间分给 rootfs 分区。</p><p>这里要注意：<code>--rootfs-size-mb</code> 和 <code>--image-size-mb</code> 不能同时使用。</p><p>为什么？因为它们都在控制容量，只是角度不同。一个说“rootfs 分区要这么大”，另一个说“整块盘要这么大”。如果同时写，脚本就要替你做取舍，这种取舍不应该偷偷发生。</p><h2 id="第五步-先做一个-boot-tree" tabindex="-1">第五步：先做一个 boot-tree <a class="header-anchor" href="#第五步-先做一个-boot-tree" aria-label="Permalink to &quot;第五步：先做一个 boot-tree&quot;">​</a></h2><p>在真正生成 ext4 之前，脚本会先准备一个临时目录：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>boot-tree/</span></span>
<span class="line"><span>├── zImage</span></span>
<span class="line"><span>├── imx6ull-aes.dtb</span></span>
<span class="line"><span>├── boot.cmd</span></span>
<span class="line"><span>└── boot/</span></span>
<span class="line"><span>    ├── zImage</span></span>
<span class="line"><span>    └── imx6ull-aes.dtb</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><code>zImage</code> 和 DTB 都来自 release 目录。<code>boot.cmd</code> 是脚本根据介质生成的启动命令。</p><p>eMMC 镜像里的 <code>boot.cmd</code> 大概是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>setenv bootargs console=ttymxc0,115200 root=/dev/mmcblk1p2 rootwait rw</span></span>
<span class="line"><span>ext4load mmc 1:1 \${loadaddr} /zImage</span></span>
<span class="line"><span>ext4load mmc 1:1 \${fdt_addr_r} /imx6ull-aes.dtb</span></span>
<span class="line"><span>bootz \${loadaddr} - \${fdt_addr_r}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>SD 镜像则会变成 <code>mmc 0:1</code> 和 <code>/dev/mmcblk0p2</code>。</p><p>这份 <code>boot.cmd</code> 不一定会被 U-Boot 自动执行，但它是很好的调试记录。你忘了这个镜像到底为哪个介质生成时，看它就知道。</p><h2 id="第六步-用-mke2fs-d-做文件系统" tabindex="-1">第六步：用 <code>mke2fs -d</code> 做文件系统 <a class="header-anchor" href="#第六步-用-mke2fs-d-做文件系统" aria-label="Permalink to &quot;第六步：用 \`mke2fs -d\` 做文件系统&quot;">​</a></h2><p>传统做镜像时，很多人会走这条路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>创建空文件 → losetup → 分区 → mount → cp → umount</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这条路能走，但脚本化起来麻烦。尤其是 mount/umount，一旦中间失败，就容易留下脏状态。</p><p>这里脚本用了更干净的方式：先分别生成两个 ext4 文件系统镜像。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>boot.ext4</span></span>
<span class="line"><span>rootfs.ext4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>核心命令是：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mke2fs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ext4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">src_dir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">label</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -F</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fs_image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><code>-d &quot;\${src_dir}&quot;</code> 是关键。它告诉 <code>mke2fs</code>：创建文件系统时，顺便把这个目录里的内容填进去。</p><p>这样脚本就不需要挂载文件系统，也不需要 root 权限。对构建系统来说，这是一个很舒服的选择。</p><h2 id="第七步-整盘镜像登场" tabindex="-1">第七步：整盘镜像登场 <a class="header-anchor" href="#第七步-整盘镜像登场" aria-label="Permalink to &quot;第七步：整盘镜像登场&quot;">​</a></h2><p>现在 boot.ext4 和 rootfs.ext4 都准备好了，脚本开始创建真正的 <code>.img</code>。</p><p>先用 <code>truncate</code> 做出一个指定大小的空文件：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">truncate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">IMAGE_SIZE_MB</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}M&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;\${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>然后用 <code>sfdisk</code> 写入 MBR 分区表：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>start=&lt;boot_start&gt;, size=&lt;boot_size&gt;, type=83, bootable</span></span>
<span class="line"><span>start=&lt;rootfs_start&gt;, size=&lt;rootfs_size&gt;, type=83</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>最后用 <code>dd</code> 把三个 payload 写进去：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=u-boot-dtb.imx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> of=image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=1K</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seek=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conv=notrunc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=boot.ext4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      of=image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">512</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seek=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">boot_star</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conv=notrunc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> if=rootfs.ext4</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    of=image</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bs=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">512</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> seek=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">rootfs_star</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> conv=notrunc</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这三次写入分别对应：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>raw U-Boot 区域</span></span>
<span class="line"><span>boot 分区内容</span></span>
<span class="line"><span>rootfs 分区内容</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>做到这里，一个完整 raw image 就出来了。</p><h2 id="第八步-manifest-是镜像说明书" tabindex="-1">第八步：manifest 是镜像说明书 <a class="header-anchor" href="#第八步-manifest-是镜像说明书" aria-label="Permalink to &quot;第八步：manifest 是镜像说明书&quot;">​</a></h2><p>脚本最后会写一个 <code>.manifest</code>。这个文件非常值得看，因为它记录了镜像到底是怎么来的。</p><p>里面会有这些信息：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>image=...</span></span>
<span class="line"><span>release_dir=...</span></span>
<span class="line"><span>uboot=...</span></span>
<span class="line"><span>kernel=...</span></span>
<span class="line"><span>dtb=...</span></span>
<span class="line"><span>rootfs=...</span></span>
<span class="line"><span>boot_media=emmc</span></span>
<span class="line"><span>uboot_mmc_dev=1</span></span>
<span class="line"><span>linux_root_dev=/dev/mmcblk1p2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>还会记录分区布局：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>layout:</span></span>
<span class="line"><span>  uboot_offset_kib=1</span></span>
<span class="line"><span>  boot_partition_start_sector=32768</span></span>
<span class="line"><span>  boot_partition_size_mib=64</span></span>
<span class="line"><span>  rootfs_partition_start_sector=163840</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>以及手动启动命令。</p><p>这份 manifest 的价值在排错时会非常明显。比如你看到 Linux 起不来，怀疑 root 设备不对，第一件事不是重新烧录，而是先打开 manifest 看：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>linux_root_dev=</span></span>
<span class="line"><span>boot_media=</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>很多问题到这里就能对上。</p><p><code>.sha256</code> 则是用来确认镜像复制或传输过程中没有损坏。</p><h2 id="和-release-all-sh-的关系" tabindex="-1">和 <code>release-all.sh</code> 的关系 <a class="header-anchor" href="#和-release-all-sh-的关系" aria-label="Permalink to &quot;和 \`release-all.sh\` 的关系&quot;">​</a></h2><p>你可以直接运行 image builder：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/image_builder/build_imx6ull_image.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --release-dir=out/release-latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>也可以让 <code>release-all.sh</code> 的 Stage 5 调它：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/release-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --boot-media</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> emmc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/release-all.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --continue</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --stage</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --boot-media</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sd</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果你正在调镜像参数，直接跑 image builder 更快；如果你想放进完整 release 流程，就走 <code>release-all.sh</code>。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>到这里，这个脚本的主线就清楚了：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解析参数</span></span>
<span class="line"><span>→ 确认 SD/eMMC</span></span>
<span class="line"><span>→ 找齐 U-Boot、zImage、DTB、rootfs</span></span>
<span class="line"><span>→ 计算分区大小</span></span>
<span class="line"><span>→ 生成 boot.ext4 和 rootfs.ext4</span></span>
<span class="line"><span>→ 写分区表和 raw payload</span></span>
<span class="line"><span>→ 输出 manifest 和 sha256</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>它不是一个神秘工具，而是一份可复现的装配流程。理解这一点之后，你就可以放心地改参数、看 manifest、查分区表，而不是把镜像当成黑盒。</p><p><strong>下一步：</strong> 阅读 <a href="./07_image_size_and_usage">07_image_size_and_usage.md</a>，专门处理镜像大小、SD/eMMC 参数和常见错误。</p>`,113)])])}const u=a(p,[["render",t]]);export{b as __pageData,u as default};
